#include <iostream>
#include <optional>

std::optional<int> findFirstDivisible(const int* arr, int size, int divisor) {
    for (int i = 0; i < size; ++i)
        if (arr[i] % divisor == 0) return arr[i];
    return std::nullopt;
}

int main() {
    int n, d;
    std::cin >> n >> d;

    int arr[20];
    for (int i = 0; i < n; ++i)
        std::cin >> arr[i];

    auto result = findFirstDivisible(arr, n, d);

    if (result)
        std::cout << "Found: " << *result << '\n';
    else
        std::cout << "Not found\n";

    return 0;
}

